export const useGetAccountInternal = (refetchInterval?: number) => {
  const accountId = useGetAccountId();
  const currentAccountQuery = useGetOneAccount({ accountId, refetchInterval });

  return {
    currentAccount: currentAccountQuery.data,
    isFetched: currentAccountQuery.isFetched,
    isLoading: currentAccountQuery.isLoading,
    refetch: currentAccountQuery.refetch,
  };
};

export const UseGetAccountContext = createContext(useGetAccountInternal);
export const useGetAccount = (refetchInterval?: number) =>
  useContext(UseGetAccountContext)(refetchInterval);

