// What document categories are required for each account category
const DOC_CATEGORIES_BY_ACCOUNT_CATEGORY = {
  'church-ministry': ['ein', 'ownership_affiliation', 'state_incorporation'],
  education: ['ein', 'ownership_affiliation'],
  nonprofit: [
    'ein',
    'ownership_affiliation',
    'state_incorporation',
    'nonprofit_determination_letter',
    // 'california_charity_registration',
  ],
  political: [
    'ein',
    'ownership_affiliation',
    'candidate_or_pac_filing',
    // 'section_527_pac_designation',
  ],
  vendor: ['ein', 'ownership_affiliation', 'state_incorporation'],
} as const;

// What documents are required for each document category
const DOCUMENTS_BY_DOC_CATEGORY = {
  ein: ['irs_cp_575'],
  ownership_affiliation: [
    'meeting_minutes',
    'articles_of_incorporation',
    'annual_report',
    'vendor_contract',
  ],
  state_incorporation: [
    'articles_of_incorporation',
    'annual_report',
    'state_registration_paperwork',
  ],
  nonprofit_determination_letter: ['irs_501c'],
  candidate_or_pac_filing: [
    'appointment_of_treasurer',
    'statement_of_organization',
    'campaign_finance_report',
    'committee_registration',
  ],
  california_charity_registration: ['state_charity_registration'],
  section_527_pac_designation: ['irs_8871'],
} as const;

export type DocumentCategory = keyof typeof DOCUMENTS_BY_DOC_CATEGORY;

export type AccountDocumentCategories = Record<DocumentCategory, AccountDocumentType[]>;

export function getRequiredDocumentCategories({
  accountCategory,
  subCategory,
  state,
}: {
  accountCategory: AccountCategory | null;
  subCategory?: string | null;
  state?: string | null;
}): Partial<Record<DocumentCategory, AccountDocumentType[]>> {
  if (!accountCategory) {
    return {};
  }

  // TODO: we should look this up from the server side endpoint so that there is one source of truth
  //  but we can keep this as a fallback for now. Note that required documents
  //  are not only tied to account category, they can be based on state like the 'california_charity_registration'
  //  or sub-category like 'section_527_pac_designation'
  const categories = [...DOC_CATEGORIES_BY_ACCOUNT_CATEGORY[accountCategory]] as DocumentCategory[];

  if (state && accountCategory === 'nonprofit' && state.toUpperCase() === 'CA') {
    categories.push('california_charity_registration');
  }
  if (subCategory && accountCategory === 'political' && subCategory === 'section_527_pac') {
    categories.push('section_527_pac_designation');
  }

  // grabbing this to double check that we'll have a set of documents to use for each category
  const docCategories: Array<keyof typeof DOCUMENTS_BY_DOC_CATEGORY> = Object.keys(
    DOCUMENTS_BY_DOC_CATEGORY
  ) as Array<keyof typeof DOCUMENTS_BY_DOC_CATEGORY>;
  const requiredDocCategories: Partial<Record<DocumentCategory, AccountDocumentType[]>> = {};

  for (const category of categories) {
    if (docCategories.includes(category)) {
      requiredDocCategories[category] = [...DOCUMENTS_BY_DOC_CATEGORY[category]];
    }
  }

  return requiredDocCategories;
}

export function getRequiredDocumentCategoriesByRequiredDocuments(
  requiredDocuments: string[]
): Partial<Record<DocumentCategory, AccountDocumentType[]>> {
  const requiredDocCategories: Partial<Record<DocumentCategory, AccountDocumentType[]>> = {};
  for (const requiredDocument of requiredDocuments) {
    if (hasKey(DOCUMENTS_BY_DOC_CATEGORY, requiredDocument)) {
      requiredDocCategories[requiredDocument] = [...DOCUMENTS_BY_DOC_CATEGORY[requiredDocument]];
    }
  }
  return requiredDocCategories;
}

export function getDocumentsByCategory(category: AccountCategory | null) {
  if (!category) {
    return [];
  }
  const docsByCategory = DOC_CATEGORIES_BY_ACCOUNT_CATEGORY[category].flatMap(
    (category) => DOCUMENTS_BY_DOC_CATEGORY[category]
  );
  // dedupe
  return [...new Set(docsByCategory)];
}

