import { ChakraProvider } from '@chakra-ui/react';
import { RenderOptions, RenderResult, render } from '@testing-library/react';
import { RenderHookOptions, renderHook } from '@testing-library/react-hooks';
import { theme } from '@ui/theme';
import { BrowserHistory } from 'history';
import React from 'react';
import { QueryClient, QueryClientProvider } from 'react-query';
import { MemoryRouter, MemoryRouterProps } from 'react-router-dom';

if (!document || !window) {
  throw new Error('testUtils cannot access document or window');
}

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      retry: false,
    },
  },
});

type AppWrapperProps = { children?: React.ReactNode; routerProps?: MemoryRouterProps };

// Children comes through the first argument of render
// we don't have to declare it again in the options
type RenderOptionProps = RenderOptions & Omit<AppWrapperProps, 'children'>;
type RenderHookOptionsProps<T> = (RenderHookOptions<T> | undefined) &
  Omit<AppWrapperProps, 'children'>;

const AppWrapper = ({ children, routerProps }: AppWrapperProps) => {
  // note: we're providing environment to Chakra to avoid
  // it incorrectly using its SSR mocks, we want to use
  // the window and document from jsdom (or other test env)
  // and not do a bad polyfill that breaks in weird ways
  return (
    <QueryClientProvider client={queryClient}>
      <ChakraProvider
        environment={{
          document,
          window,
        }}
        theme={theme}
      >
        <MemoryRouter {...routerProps}>{children}</MemoryRouter>
      </ChakraProvider>
    </QueryClientProvider>
  );
};

const customRender = (ui: React.ReactElement, options?: RenderOptionProps): RenderResult => {
  const { routerProps, ...rest } = options ?? {};
  return render(ui, {
    wrapper: (props) => <AppWrapper {...props} routerProps={routerProps} />,
    ...rest,
  });
};

const customRenderHook = <TProps, TResult>(
  callback: (props: TProps) => TResult,
  options?: RenderHookOptionsProps<TProps> | undefined
) => {
  const { routerProps, ...rest } = options ?? {};
  return renderHook(callback, {
    wrapper: (props) => <AppWrapper {...props} routerProps={routerProps} />,
    ...rest,
  });
};

export { customRender as render, customRenderHook as renderHook };

export interface HistoryRouterProps {
  basename?: string;
  children?: React.ReactNode;
  history: BrowserHistory;
}

